export const EmailMessageSchema = {
  type: "object",
  additionalProperties: false,
  required: [
    "id",
    "from",
    "to",
    "subject",
    "category",
    "status",
    "accepted_count",
    "processed_count",
    "delivered_count",
    "bounced_count",
    "complained_count",
    "deferred_count",
    "rejected_count",
    "open_count",
    "click_count",
    "track_opens",
    "track_clicks",
    "created_at",
  ],
  properties: {
    id: {
      readOnly: true,
      $ref: "#/components/schemas/EmailID",
      description: "Message ID.",
    },
    from: {
      $ref: "#/components/schemas/EmailAddress",
      description:
        "Sender address. `name` is present when a display name was provided on the send.",
    },
    to: {
      type: "array",
      items: {
        $ref: "#/components/schemas/EmailAddress",
      },
      minItems: 1,
      maxItems: 50,
      description:
        "Primary recipients. Length is the recipient count; use the broadcasts endpoint for audience-targeted sends. Each entry's `name` is present when a display name was provided on the send.",
    },
    cc: {
      type: "array",
      items: {
        $ref: "#/components/schemas/EmailAddress",
      },
      description: "CC recipients.",
    },
    bcc: {
      type: "array",
      items: {
        $ref: "#/components/schemas/EmailAddress",
      },
      description: "BCC recipients.",
    },
    subject: {
      type: "string",
      minLength: 1,
      description: "Message subject line.",
    },
    category: {
      type: "string",
      minLength: 1,
      enum: ["marketing", "transactional"],
      description:
        "Content classification. Controls suppression policy — `marketing` blocks on all suppression reasons; `transactional` allows delivery through complaint and unsubscribe suppressions.\n",
    },
    reply_to: {
      type: ["array", "null"],
      items: {
        $ref: "#/components/schemas/EmailAddress",
      },
      maxItems: 25,
      description:
        "Reply-To addresses, if set on the send. Empty/null when no Reply-To was provided.",
    },
    status: {
      readOnly: true,
      allOf: [
        {
          $ref: "#/components/schemas/EmailMessageStatus",
        },
      ],
      description:
        "Aggregate delivery status derived from recipient states. `scheduled` means the message is queued to send at a future time and has not been dispatched yet. `accepted` means Bird has the send and is preparing to deliver. `processed` means Bird has processed the message and queued it for delivery to the recipient's mail server. `canceled` means a scheduled message was canceled before it was sent.\n",
    },
    accepted_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description:
        "Number of recipients currently in the `accepted` state — Bird has the send and is preparing to deliver.",
    },
    processed_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description:
        "Number of recipients for whom Bird has processed the message and queued it for delivery.",
    },
    delivered_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description:
        "Number of recipients whose messages were accepted by the remote MTA.",
    },
    bounced_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description:
        "Number of recipients that resulted in a permanent delivery failure.",
    },
    complained_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description: "Number of recipients that reported spam.",
    },
    deferred_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description:
        "Number of recipients in transient delivery deferral; the provider is retrying.",
    },
    rejected_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description:
        "Number of recipients rejected before delivery. See the per-recipient `rejection_reason` field on `GET /v1/email/messages/{message_id}/recipients` for the specific cause (suppression match, transmission failure, generation failure, or policy refusal).\n",
    },
    processing_latency_ms: {
      type: ["integer", "null"],
      minimum: 0,
      readOnly: true,
      description:
        "Time between Bird accepting the send and the message being processed for delivery, in milliseconds, for the fastest recipient. Null until the first recipient reaches `processed`.\n",
    },
    delivery_latency_ms: {
      type: ["integer", "null"],
      minimum: 0,
      readOnly: true,
      description:
        "Time between the message being processed and the receiving mail server accepting it, in milliseconds, for the fastest delivered recipient. Null until the first recipient is delivered.\n",
    },
    total_latency_ms: {
      type: ["integer", "null"],
      minimum: 0,
      readOnly: true,
      description:
        "End-to-end accept → delivered time for the fastest delivered recipient, in milliseconds. Null until the first recipient is delivered.\n",
    },
    open_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description: "Total open events across all recipients.",
    },
    click_count: {
      type: "integer",
      readOnly: true,
      default: 0,
      description: "Total click events across all recipients.",
    },
    tags: {
      type: "array",
      items: {
        $ref: "#/components/schemas/Tag",
      },
      description:
        "Structured `{name, value}` filter labels applied to this send. See EmailMessageSendRequest for the tags vs metadata distinction.",
    },
    metadata: {
      type: "object",
      description:
        "Arbitrary JSON metadata stored on the message object and echoed in webhook payloads. See EmailMessageSendRequest for the tags vs metadata distinction.",
      additionalProperties: true,
    },
    attachments: {
      type: "array",
      items: {
        $ref: "#/components/schemas/EmailAttachmentRef",
      },
      description:
        "Attachment metadata for the send. Empty when no attachments were included. Raw content is not echoed; use the future content-retrieval endpoint when storage is enabled.",
    },
    track_opens: {
      type: "boolean",
      description: "Whether open tracking is enabled for this send.",
    },
    track_clicks: {
      type: "boolean",
      description: "Whether click tracking is enabled for this send.",
    },
    created_at: {
      type: "string",
      format: "date-time",
      minLength: 1,
      readOnly: true,
      description: "When the send request was accepted.",
    },
    thread_id: {
      type: ["string", "null"],
      readOnly: true,
      pattern: "^thr_[0-9a-hjkmnp-tv-z]{26}$",
      description:
        "Thread this message belongs to. Null until threading is enabled.",
    },
    in_reply_to_message_id: {
      readOnly: true,
      description: "The message this one is a reply to, if any.",
      oneOf: [
        {
          $ref: "#/components/schemas/EmailID",
        },
        {
          type: "null",
        },
      ],
    },
    delivered_at: {
      type: ["string", "null"],
      format: "date-time",
      readOnly: true,
      description:
        "When all recipients reached a terminal delivered state, or null if not yet fully delivered.",
    },
    scheduled_at: {
      type: ["string", "null"],
      format: "date-time",
      readOnly: true,
      description:
        "When this message is scheduled to send, for a send created with a future send time. Null for an immediate send. Stays set after the scheduled send fires.",
    },
  },
} as const;

